require "config.SeasonConfig"

GUIGameResultItem = class("GUIGameResultItem", IGUIWindow)

function GUIGameResultItem:onLoad()
    self.index = 0
    self.honorId = 0
    self.content = self:getChildWindow(0, GUIType.Layout)
    self.tvRank = self:getChildWindow(0, GUIType.StaticText, self.content)
    self.ivDan = self:getChildWindow(1, GUIType.StaticImage, self.content)
    self.tvName = self:getChildWindow(2, GUIType.StaticText, self.content)

    self.tvKills = self:getChildWindow(3, GUIType.StaticText, self.content)
    self.tvScore = self:getChildWindow(4, GUIType.StaticText, self.content)

end

function GUIGameResultItem:initItem(data)
    self.honorId = data.honorId
    if data.rank <= 3 then
        self.tvRank:SetFont(GUIFontManager:Instance():GetFont("HT20"))
        if data.rank == 1 then
            self.tvRank:SetTextColor({ 255 / 255, 223 / 255, 0 })
        elseif data.rank == 2 then
            self.tvRank:SetTextColor({ 143 / 255, 235 / 255, 255 / 255 })
        else
            self.tvRank:SetTextColor({ 255 / 255, 77 / 255, 59 / 255 })
        end
    end
    self.tvName:SetText(Lang:getString(tostring(data.name)))
    self.tvRank:SetText(tostring(data.rank))
    self.tvKills:SetText(tostring(data.kills))

    local curSeason = SeasonConfig:getSeasonByHonorId(self.honorId)
    if not curSeason then
        return
    end
    self.ivDan:SetImage(curSeason.danIcon)
    local scoreText = "+" .. data.result_add_integral
    if tonumber(data.result_add_integral) < 0 then
        scoreText = data.result_add_integral
    end
    self.tvScore:SetText(scoreText)
end

return GUIGameResultItem